$p = "$env:USERPROFILE\Apps\fzf"; New-Item -ItemType Directory -Path $p -Force; $code = 'using System; using System.Diagnostics; class Proxy { static void Main(string[] args) { var si = new ProcessStartInfo("fzf.cmd") { Arguments = string.Join(" ", args), UseShellExecute = false }; try { using (var p = Process.Start(si)) { p.WaitForExit(); Environment.Exit(p.ExitCode); } } catch { Environment.Exit(1); } } }'; Add-Type -TypeDefinition $code -OutputAssembly "$p\fzf.exe" -OutputType ConsoleApplication; $currentPath = [Environment]::GetEnvironmentVariable('Path', 'User'); if ($currentPath -notlike "*$p*") { [Environment]::SetEnvironmentVariable('Path', "$currentPath;$p", 'User') }
